class class_calculate_sqa():
    def __init__(self, input_time, input_signal, input_params, bandpass, dashboardMode, nfft, delta_peakdet, matching_index=None):

        self.params = input_params.copy()

        prepro_signal = signal_processing() # input to signal processing
        mva_time, mva_val = prepro_signal.moving_average(input_time, input_signal, self.params['window_mva'])

        # prepro_signal = signal_processing(np.vstack([input_time, input_signal]).T, self.params)
        bl_time, bl_val = prepro_signal.baseline(mva_time, mva_val, self.params['window_bl'])
        baseline_time, blrm_val = prepro_signal.baseline_removal(mva_time, mva_val, bl_time, bl_val)
        self.signal_input = np.vstack([baseline_time, blrm_val]).T

        # if matching_index is not None:
        index = np.arange(len(input_time))
        mva_index, temp_mva_val = prepro_signal.moving_average(index, input_signal, self.params['window_mva'])
        bl_index, temp_bl_val = prepro_signal.baseline(mva_index, temp_mva_val, self.params['window_bl'])
        self.signal_index = bl_index

        self.matching_index = matching_index

        self.sampling_time = self.params["sampling_time"]
        
        self.window_length = self.params["window_size"]
        self.window_shift = self.params["window_shift"]

        self.bandpass = bandpass
        self.nfft = nfft

        self.delta_peakdet = delta_peakdet

        self.mode = dashboardMode

        self.sqa_bandpass_rr_individual_frame = 0.65
        self.sqa_threshold_rr_pos_to_neg_peak = 0.9
        self.sqa_bandpass_hr_individual_frame = 0.65
        self.sqa_threshold_hr_pos_to_neg_peak = 0.9

        self.harmonic_accpeted = 0.015

    def calculate_sqa(self, windowSignal, nfft, fs, bandpass, delta_peakdet):
        windowSignal = windowSignal - np.mean(windowSignal)

        freq, mag = compute_power_spectrum(windowSignal, fs, nfft)
        freq_wo_bp, mag_wo_bp = freq.copy(), mag.copy()

        """
        find 1st and 2nd peak
        """
        freq_bp = freq_wo_bp[(freq_wo_bp>=bandpass[0])&(freq_wo_bp<=bandpass[1])].copy()
        mag_bp = mag_wo_bp[(freq_wo_bp>=bandpass[0])&(freq_wo_bp<=bandpass[1])].copy()

        maxtab, mintab = peakdet(mag_bp, delta_peakdet, freq_bp)
        # print(len(maxtab), maxtab)
        try:
            if maxtab[0,0]<bandpass[0]+(freq_bp[2]-freq_bp[1]): # if first peak is close to cutoff frequency
                try:
                    maxtab = maxtab[1:, :]
                except:
                    pass
        except:
            pass

        if len(maxtab)>0:
            first_magpeak = [-np.Inf, -np.Inf]
            for i in range(len(maxtab)):
                if maxtab[i,1]>first_magpeak[1]:
                    first_magpeak[0] = maxtab[i,0]
                    first_magpeak[1] = maxtab[i,1]
        
            maxtab_remove_max = maxtab[maxtab[:,1]!=np.max(maxtab[:,1]), :]
            second_magpeak = [-np.Inf, -np.Inf]
            for i in range(len(maxtab_remove_max)):
                if maxtab_remove_max[i,1]>second_magpeak[1]:
                    second_magpeak[0] = maxtab_remove_max[i,0]
                    second_magpeak[1] = maxtab_remove_max[i,1]
            
            if second_magpeak[1]==-np.Inf:
                second_magpeak = [0, 0]
            
            """
            check harmonic
            """
            if (second_magpeak[0]>first_magpeak[0]*2-self.harmonic_accpeted) and (second_magpeak[0]<first_magpeak[0]*2+self.harmonic_accpeted):
                # print("second peak {:.3f} is harmonic of first peak {:.3f}".format(second_magpeak[0], first_magpeak[0]))
                second_magpeak[1] = 0
            
            diffMag = first_magpeak[1]-second_magpeak[1]
            normDiffMag = diffMag/first_magpeak[1]

        else:
            first_magpeak = [0, 0]
            second_magpeak = [0, 0]

            diffMag = 0
            normDiffMag = 0

            maxtab = np.array([[0,0], [0,0]])
        

        # import matplotlib.pyplot as plt
        # plt.figure()
        # plt.subplot(211)
        # plt.plot(np.arange(len(windowSignal))*1/fs, windowSignal)
        # plt.title(normDiffMag)
        # plt.subplot(212)
        # plt.plot(freq_bp, mag_bp)
        # plt.scatter(first_magpeak[0], first_magpeak[1])
        # plt.scatter(second_magpeak[0], second_magpeak[1])
        # plt.show()

        """
        check if pos peak to neg peak difference is sufficient
        """
        leftNegativePeak = [None, None]
        rightNegativePeak = [None, None]

        for i in range(len(mintab)-1, -1, -1):
            if (mintab[i,0]<first_magpeak[0]):
                leftNegativePeak = [mintab[i,0], mintab[i,1]]
                break
        
        if leftNegativePeak[0]==None:
            leftNegativePeak[0] = freq_bp[0]
            leftNegativePeak[1] = mag_bp[0]
            # print('leftNegativePeak[0]==None')
            
        diffMagLeft = first_magpeak[1]-leftNegativePeak[1]
        normDiffMagLeft = diffMagLeft/first_magpeak[1]
        # print('{}, {}'.format(leftNegativePeak, normDiffMagLeft))
        
        for i in range(0, len(mintab)):
            if (mintab[i,0]>first_magpeak[0]):
                rightNegativePeak = [mintab[i,0], mintab[i,1]]
                break
        
        if rightNegativePeak[0]==None:
            rightNegativePeak[0] = freq_bp[-1]
            rightNegativePeak[1] = mag_bp[-1]
            
        diffMagRight = first_magpeak[1]-rightNegativePeak[1]
        normDiffMagRight = diffMagRight/first_magpeak[1]

        # print(i)
        # print('{}, {}'.format(leftNegativePeak, rightNegativePeak))

        # """
        # if sqa is good, get bpm
        # """
        # if normDiffMag>=th_sqa:
        
        # if (normDiffMag>=0.65) and (normDiffMagLeft>=0.9) and (normDiffMagRight>=0.9):
        
        #     import matplotlib.pyplot as plt
        #     timerange = np.arange(len(windowSignal))*self.sampling_time
        #     plt.figure()
        #     plt.subplot(211)
        #     plt.plot(timerange, windowSignal)
        #     plt.title('center {:.3f}\nleft {:.3f}\nright {:.3f}'.format(normDiffMag, normDiffMagLeft, normDiffMagRight))
        #     plt.subplot(212)
        #     plt.plot(freq_bp, mag_bp)
        #     plt.scatter(first_magpeak[0], first_magpeak[1])
        #     plt.scatter(second_magpeak[0], second_magpeak[1])
        #     plt.scatter(leftNegativePeak[0], leftNegativePeak[1])
        #     plt.scatter(rightNegativePeak[0], rightNegativePeak[1])
        #     plt.show()

        return normDiffMag, normDiffMagLeft, normDiffMagRight, first_magpeak, second_magpeak, freq_bp, mag_bp

    def run(self):
        self.output_sqa = []
        # self.timeOutput = []

        self.output_good_sqa = []

        self.output_bpm = []
        self.output_bpm_w_sqa = [] # keep bpm only if sqa is good

        self.output_time_w_sqa = []
        self.output_time_wo_sqa = []

        self.list_sd_signal_w_sqa = []

        self.output_td = []
        self.output_dc = []

        if self.mode=='RR':
            th_sqa = self.sqa_bandpass_rr_individual_frame
            th_sqa_pos_neg_peak = self.sqa_threshold_rr_pos_to_neg_peak
        elif self.mode=='HR':
            th_sqa = self.sqa_bandpass_hr_individual_frame
            th_sqa_pos_neg_peak = self.sqa_threshold_hr_pos_to_neg_peak
        
        # signal = self.signal_mva
        signal = self.signal_input
                    
        wlength = self.window_length
        wshift = self.window_shift

        fs = 1/self.sampling_time

        nfft = self.nfft
        bandpass = self.bandpass
        delta_peakdet = self.delta_peakdet

        self.total_frame = 0
        self.accepted_frame = 0

        
        for i in range(0, len(signal)-wlength, wshift):
            
            current_time = signal[i+wlength, 0]
            # print(current_time)

            if self.matching_index is not None:
                current_index = self.signal_index[i]
                if current_index not in self.matching_index:
                    continue

                        
            windowSignal = signal[i:i+wlength, 1]
            # windowSignal_w_dc = windowSignal.copy()

            normDiffMag, normDiffMagLeft, normDiffMagRight, first_magpeak, second_magpeak, freq_bp, mag_bp = self.calculate_sqa(windowSignal, nfft, fs, bandpass, delta_peakdet)

            """
            get sqa
            """
            self.output_sqa = np.append(self.output_sqa, normDiffMag)

            """
            get bpm
            """
            # freqPeak, magPeak = self.findMaxPeak(freq_bp, mag_bp)
            # freqPeak, magPeak = first_magpeak[0], first_magpeak[1]

            # bpm = freqPeak*60
            bpm = first_magpeak[0]*60
            self.output_bpm = np.append(self.output_bpm, bpm)
            
            self.output_time_wo_sqa = np.append(self.output_time_wo_sqa, current_time)

            self.total_frame+=1

            """
            if sqa is good, get bpm
            """
            if (normDiffMag>=th_sqa) and (normDiffMagLeft>=th_sqa_pos_neg_peak) and (normDiffMagRight>=th_sqa_pos_neg_peak):
                self.output_bpm_w_sqa = np.append(self.output_bpm_w_sqa, bpm)
                self.output_good_sqa = np.append(self.output_good_sqa, normDiffMag)

                self.accepted_frame+=1

                # import matplotlib.pyplot as plt
                # print(np.std(signal[i:i+wlength, 1]), normDiffMag, normDiffMagLeft, normDiffMagRight)
                # plt.figure()
                # plt.subplot(211)
                # plt.plot(signal[i:i+wlength, 0], signal[i:i+wlength, 1])
                # plt.title(normDiffMag)
                # plt.subplot(212)
                # plt.plot(freq_bp, mag_bp)
                # plt.scatter(first_magpeak[0], first_magpeak[1])
                # plt.show()

                self.output_time_w_sqa = np.append(self.output_time_w_sqa, current_time)
                self.list_sd_signal_w_sqa = np.append(self.list_sd_signal_w_sqa, np.std(windowSignal))


                
def run_sqa(timestamp, signal, params, bandpass, threshold, dashboardMode, nfft, delta_peakdet, matching_index=None):
    """
    2 = good
    1 = moderate
    0 = bad
    """
    # (input_time, input_signal, input_params, bandpass, dashboardMode, nfft=settings.nfft, delta_peakdet=settings.delta_peakdet
    

    sqa = class_calculate_sqa(timestamp, signal, params, bandpass, dashboardMode, nfft, delta_peakdet, matching_index)
    sqa.run()

    # cal_sqa = sqa.output_sqa
    cal_sqa = sqa.output_good_sqa # only good sqa value

    temp_sqa_val = np.median(cal_sqa)
    if np.isnan(temp_sqa_val):
        temp_sqa_val = 0
    


    list_sd_signal_w_sqa = sqa.list_sd_signal_w_sqa
    val_sd_signal_w_sqa = np.median(list_sd_signal_w_sqa)
    if np.isnan(val_sd_signal_w_sqa):
        val_sd_signal_w_sqa = 0

    """
    BPM
    """
    bpm_wo_sqa = sqa.output_bpm # every frame, regardless sqa
    bpm_w_sqa = sqa.output_bpm_w_sqa # only frame with good SQA


    output_sqa = []
    if (temp_sqa_val<threshold[0]):
        output_sqa = 0
    elif (temp_sqa_val>=threshold[0]) & (temp_sqa_val<threshold[1]):
        output_sqa = 1
    elif (temp_sqa_val>=threshold[1]):
        output_sqa = 2


    """
    frame accapted by SQA
    """
    total_frame = sqa.total_frame
    accepted_frame = sqa.accepted_frame
    
    """
    for debugging
    """
    output_time_w_sqa = sqa.output_time_w_sqa
    output_time_wo_sqa = sqa.output_time_wo_sqa


    """
    extract breathing pattern
    """
    dict_breathing_pattern = {
        "TD": sqa.output_td,
        "DC": sqa.output_dc,
        # "|Ti-Te|/Tt": sqa.output_breathing_a,
        }
    
    
    return_output = {
        "val_sd_signal_w_sqa": val_sd_signal_w_sqa,
        "list_sd_signal_w_sqa": list_sd_signal_w_sqa
    }


    return output_sqa, temp_sqa_val, bpm_wo_sqa, bpm_w_sqa, accepted_frame, total_frame, output_time_w_sqa, output_time_wo_sqa, return_output, dict_breathing_pattern
